manifest_content:
[workspace]
resolver = "2"
members = [
  "crates",
  "crates/adapters/architect_ax",
  "crates/adapters/betfair",
  "crates/adapters/binance",
  "crates/adapters/bitmex",
  "crates/adapters/blockchain",
  "crates/adapters/bybit",
  "crates/adapters/coinbase",
  "crates/adapters/databento",
  "crates/adapters/deribit",
  "crates/adapters/derive",
  "crates/adapters/dydx",
  "crates/adapters/hyperliquid",
  "crates/adapters/interactive_brokers",
  "crates/adapters/kraken",
  "crates/adapters/lighter",
  "crates/adapters/okx",
  "crates/adapters/polymarket",
  "crates/adapters/sandbox",
  "crates/adapters/tardis",
  "crates/analysis",
  "crates/backtest",
  "crates/cli",
  "crates/common",
  "crates/core",
  "crates/cryptography",
  "crates/data",
  "crates/event_store",
  "crates/execution",
  "crates/indicators",
  "crates/infrastructure",
  "crates/live",
  "crates/model",
  "crates/network",
  "crates/persistence",
  "crates/persistence/macros",
  "crates/plugin",
  "crates/portfolio",
  "crates/pyo3",
  "crates/risk",
  "crates/serialization",
  "crates/system",
  "crates/testkit",
  "crates/trading",
  "examples/tutorials",
]

[workspace.package]
version = "0.61.0"
edition = "2024"
rust-version = "1.97.1"
authors = ["Nautech Systems <info@nautechsystems.io>"]
license = "LGPL-3.0-or-later"
readme = "README.md"
description = "Production-grade Rust-native trading engine with deterministic event-driven architecture"
categories = ["finance", "simulation", "asynchronous"]
keywords = [
  "finance",
  "trading",
  "trading-platform",
  "algorithmic-trading",
  "quantitative-finance",
]
documentation = "https://nautilustrader.io/docs"
repository = "https://github.com/nautechsystems/nautilus_trader"
homepage = "https://nautilustrader.io"

[workspace.dependencies]
nautilus-analysis = { path = "crates/analysis", version = "0.61.0" }
nautilus-backtest = { path = "crates/backtest", version = "0.61.0" }
nautilus-cli = { path = "crates/cli", version = "0.61.0" }
nautilus-common = { path = "crates/common", version = "0.61.0" }
nautilus-core = { path = "crates/core", version = "0.61.0" }
nautilus-cryptography = { path = "crates/cryptography", version = "0.61.0" }
nautilus-data = { path = "crates/data", version = "0.61.0" }
nautilus-execution = { path = "crates/execution", version = "0.61.0" }
nautilus-indicators = { path = "crates/indicators", version = "0.61.0" }
nautilus-infrastructure = { path = "crates/infrastructure", version = "0.61.0" }
nautilus-live = { path = "crates/live", version = "0.61.0", default-features = false }
nautilus-model = { path = "crates/model", version = "0.61.0" }
nautilus-network = { path = "crates/network", version = "0.61.0" }
nautilus-persistence = { path = "crates/persistence", version = "0.61.0" }
nautilus-persistence-macros = { path = "crates/persistence/macros", version = "0.61.0" }
nautilus-portfolio = { path = "crates/portfolio", version = "0.61.0" }
nautilus-pyo3 = { path = "crates/pyo3", version = "0.61.0" }
nautilus-risk = { path = "crates/risk", version = "0.61.0" }
nautilus-serialization = { path = "crates/serialization", version = "0.61.0" }
nautilus-system = { path = "crates/system", version = "0.61.0" }
nautilus-testkit = { path = "crates/testkit", version = "0.61.0" }
nautilus-trading = { path = "crates/trading", version = "0.61.0" }

# -----------------------------------------------------------------------------
# Adapters
#
# Note: default-features = false to control high-precision separately (not supported on Windows)
# -----------------------------------------------------------------------------
nautilus-architect-ax = { path = "crates/adapters/architect_ax", version = "0.61.0" }
nautilus-betfair = { path = "crates/adapters/betfair", version = "0.61.0", default-features = false }
nautilus-binance = { path = "crates/adapters/binance", version = "0.61.0", default-features = false }
nautilus-bitmex = { path = "crates/adapters/bitmex", version = "0.61.0", default-features = false }
nautilus-blockchain = { path = "crates/adapters/blockchain", version = "0.61.0" }
nautilus-bybit = { path = "crates/adapters/bybit", version = "0.61.0", default-features = false }
nautilus-coinbase = { path = "crates/adapters/coinbase", version = "0.61.0", default-features = false }
nautilus-databento = { path = "crates/adapters/databento", version = "0.61.0", default-features = false }
nautilus-deribit = { path = "crates/adapters/deribit", version = "0.61.0", default-features = false }
nautilus-derive = { path = "crates/adapters/derive", version = "0.61.0", default-features = false }
nautilus-dydx = { path = "crates/adapters/dydx", version = "0.61.0", default-features = false }
nautilus-hyperliquid = { path = "crates/adapters/hyperliquid", version = "0.61.0", default-features = false }
nautilus-interactive-brokers = { path = "crates/adapters/interactive_brokers", version = "0.61.0" }
nautilus-kraken = { path = "crates/adapters/kraken", version = "0.61.0", default-features = false }
nautilus-lighter

{
  "name": "tradingview-mcp",
  "version": "1.0.0",
  "description": "MCP bridge for TradingView Desktop via Chrome DevTools Protocol",
  "type": "module",
  "main": "src/server.js",
  "bin": {
    "tv": "src/cli/index.js"
  },
  "exports": {
    ".": "./src/server.js",
    "./core": "./src/core/index.js"
  },
  "scripts": {
    "start": "node src/server.js",
    "tv": "node src/cli/index.js",
    "lint": "eslint src/",
    "test": "node --test tests/e2e.test.js tests/pine_analyze.test.js",
    "test:e2e": "node --test tests/e2e.test.js",
    "test:unit": "node --test tests/pine_analyze.test.js tests/cli.test.js tests/sanitization.test.js tests/replay.test.js tests/launch.test.js tests/chart_indicator.test.js tests/chart_history.test.js tests/update.test.js",
    "test:cli": "node --test tests/cli.test.js",
    "test:all": "node --test tests/e2e.test.js tests/pine_analyze.test.js tests/cli.test.js tests/sanitization.test.js tests/replay.test.js tests/launch.test.js tests/chart_indicator.test.js tests/chart_history.test.js tests/update.test.js",
    "test:verbose": "node --test --test-reporter=spec tests/e2e.test.js tests/pine_analyze.test.js",
    "test:count": "node --test --test-reporter=spec tests/e2e.test.js 2>&1 | tail -5"
  },
  "dependencies": {
    "@modelcontextprotocol/sdk": "^1.12.1",
    "chrome-remote-interface": "^0.33.2"
  },
  "devDependencies": {
    "eslint": "^9.39.4"
  }
}

